VALUES 

('VWTmaSim000010','dynamic.maSimsHelper.10','MA SIMS Error 10','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;10</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp; Days in Membership-Average Days in membership too low&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">For in-district students\, the sum of all days in membership divided by the number of students\, must be greater than or equal to 150 days. &amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Steps to resolve:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">Verify the days in membership of these students is at least 150 and that no Prev Adj Membership values on membership records are affecting this value.</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 11" label="DOE 11" label-short="false" />        </line>      </block>    </row>    <row>      <block>        <line border="none">          <text underline="true" font-size="medium">ENROLLMENT HISTORY</text>        </line>        <line border="none">          <spacer height="2" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <embedded-list id="student-enrollment" relationship="relStdEnrOid" selection-type="none" embedded-edit="true" show-blob-text="true" warn-on-delete="true" independent-save="true">              <field alias="enr-date" sort="true" />              <field id="enrEnrType" />              <field id="enrEnrStatus" />              <field id="enrEnrCode" />              <field id="relEnrSklOid.sklSchoolName" />              <field alias="ENR Prev DOE Adjusted Status" />              <field alias="ENR Prev DOE Adjusted School" />              <field alias="ENR Prev DOE Adjusted Member" />              <field alias="ENR Prev DOE Adjusted Attend" />              <field alias="ENR Prev DOE 13" />              <field alias="ENR Prev DOE 11" />              <field alias="ENR Prev Calendar" />            </embedded-list>          </cell>        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim000101','dynamic.maSimsHelper.101','MA SIMS Error 101','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;101</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Student SASID from last period is missing&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">Missing StudentSchoolEnrollment.&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">If you receive this error\, please contact Technical Support for assistance.</text>        </line>        <line border="bottom">          <text bold="true" font-size="medium">Call: 888-244-1366\, option 1</text>        </line>      </block>    </row>    <row>      <block>        <line border="none">          <text underline="true" font-size="medium">ENROLLMENT HISTORY</text>        </line>        <line border="none">          <spacer height="2" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <embedded-list id="student-enrollment" relationship="relStdEnrOid" selection-type="none" embedded-edit="true" show-blob-text="true" warn-on-delete="true" independent-save="true">              <field alias="enr-date" sort="true" />              <field id="enrEnrType" />              <field id="enrEnrStatus" />              <field id="enrEnrCode" />              <field id="relEnrSklOid.sklSchoolName" />              <field alias="ENR Prev DOE Adjusted Status" />              <field alias="ENR Prev DOE Adjusted School" />              <field alias="ENR Prev DOE Adjusted Member" />              <field alias="ENR Prev DOE Adjusted Attend" />              <field alias="ENR Prev DOE 13" />              <field alias="ENR Prev DOE 11" />              <field alias="ENR Prev Calendar" />            </embedded-list>          </cell>        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim101345','dynamic.maSimsHelper.101345','MA SIMS Error 101345','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;101345</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Invalid Grad Core curriculum code&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">The code entered is invalid. Refer to valid values for DOE037 - Graduate\, Completed Mass Core Curriculum in the Data Handbook.&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Steps to resolve:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">If DOE012=04\, then DOE033 cannot = 500 and DOE037 cannot = 00.</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 12" label="DOE 12" label-short="false" />        </line>		<line border="none">          <property alias="DOE 33" label="DOE 33" label-short="false" />        </line>		<line border="none">          <property alias="DOE 37" label="DOE 37" label-short="false" />        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim101384','dynamic.maSimsHelper.101384','MA SIMS Error 101384','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;101384</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp; School Code (DOE015) not valid with SPED Placement code Age 6:21(DOE034)&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">If school code = 037000xx (one of the institutional schools) then Sped Placement (DOE034) must = 90 for students age 6-21.&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>		<line border="none">          <property id="relStdSklOid.sklFieldA006" label="DOE 15" label-short="false" />        </line>        <line border="none">          <property alias="DOE Adjusted School" label="Adjusted School" label-short="false" />        </line>		<line border="none">          <property alias="DOE 34" label="DOE 34" label-short="false" />        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim101452','dynamic.maSimsHelper.101452','MA SIMS Error 101452','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">101452</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">Enrollment Status(DOE012) = 40 requires a SPED Level of Need Code (DOE038)</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">DOE 40 - Special Education - Evaluation Results cannot have a state code of 00. Must have a code other than 00.</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Steps to resolve:</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">1. Update the student&#39;s DOE 12 to Active</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">2. Update Adjusted Status to Not Enrolled/SPED Only or the equivalent value for your district</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">3. Check "Adjusted Service Only" on the most recent membership record.</text>          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Note:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">These errors won&#39;t clear until SPED is pulled mid-day/overnight.</text>            <spacer width="15" />          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">SPED Level of Need Code (DOE038) cannot be 500 when Enrollment Status (DOE012) = 40 or 41.</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 12" label="DOE 12" label-short="false" />        </line>        <line border="none">          <property alias="DOE Adjusted Status" label="Adjusted Status" label-short="false" />        </line>        <line border="none">          <property alias="DOE 38" label="DOE 38" label-short="false" />        </line>      </block>    </row>    <row>      <block>        <line border="none">          <text underline="true" font-size="medium">ENROLLMENT HISTORY</text>        </line>        <line border="none">          <spacer height="2" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <embedded-list id="student-enrollment" relationship="relStdEnrOid" selection-type="none" embedded-edit="true" show-blob-text="true" warn-on-delete="true" independent-save="true">              <field alias="enr-date" sort="true" />              <field id="enrEnrType" />              <field id="enrEnrStatus" />              <field id="enrEnrCode" />              <field id="relEnrSklOid.sklSchoolName" />              <field alias="ENR Prev DOE Adjusted Status" />              <field alias="ENR Prev DOE Adjusted School" />              <field alias="ENR Prev DOE Adjusted Member" />              <field alias="ENR Prev DOE Adjusted Attend" />              <field alias="ENR Prev DOE 13" />              <field alias="ENR Prev DOE 11" />              <field alias="ENR Prev Calendar" />            </embedded-list>          </cell>        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim101474','dynamic.maSimsHelper.101474','MA SIMS Error 101474','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;Graduates: High School Completer Plans code (DOE033) invalid with enrollment status</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Steps to resolve:</text>          <spacer height="15" />        </line>        <line border="none">          <spacer height="15" width="10" />          <text font-size="medium">If enrollment status (DOE012)=04:</text>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">1. High School Completer Plans (DOE033)must be 01-09.</text>          </cell>        </line>        <line border="none">          <spacer height="15" width="10" />          <text font-size="medium">If enrollment status (DOE012)=10 or 11:</text>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">1. High School Completer Plans (DOE033) can be 01-09.</text>          </cell>        </line>        <line border="none">          <spacer height="15" width="10" />          <text font-size="medium">&amp;nbsp;If enrollment status (DOE012) does not equal 04:</text>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">1. High School Completer Plans (DOE033) must be 500.</text>          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 12" label="DOE 12" label-short="false" />        </line>        <line border="none">          <property alias="DOE 33" label="DOE 33" label-short="false" />        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim101491','dynamic.maSimsHelper.101491','MA SIMS Error 101491','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;101491</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;SPED students must have other SPED data elements</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">Student reporting special education status in DOE32 or DOE034 must also report significant values in DOE036\, DOE038 and DOE040.&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 32" label="DOE 32" label-short="false" />        </line>        <line border="none">          <property alias="DOE 34" label="DOE 34" label-short="false" />        </line>        <line border="none">          <property alias="DOE 36" label="DOE 36" label-short="false" />        </line>        <line border="none">          <property alias="DOE 38" label="DOE 38" label-short="false" />        </line>        <line border="none">          <property alias="DOE 40" label="DOE 40" label-short="false" />        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim101492','dynamic.maSimsHelper.101492','MA SIMS Error 101492','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;101492</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;SPED data elements not needed for non:SPED student&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">If Sped Placement age 6-21 (DOE034) = 00 and Sped Placement age 3-5 (DOE032) = 00\, 05 then all other special education data elements must not be 500 (DOE036 should be 500\, DOE038 should be 500 and DOE040 should be (00 or 02 or 08 or 09)). &amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Note:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">If any changes are made to any SPED values\, you will need to wait until SPED pulls overnight for the error to clear</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 32" label="DOE 32" label-short="false" />        </line>        <line border="none">          <property alias="DOE 33" label="DOE 33" label-short="false" />        </line>        <line border="none">          <property alias="DOE 34" label="DOE 34" label-short="false" />        </line>        <line border="none">          <property alias="DOE 35" label="DOE 35" label-short="false" />        </line>        <line border="none">          <property alias="DOE 36" label="DOE 36" label-short="false" />        </line>        <line border="none">          <property alias="DOE 37" label="DOE 37" label-short="false" />        </line>        <line border="none">          <property alias="DOE 38" label="DOE 38" label-short="false" />        </line>        <line border="none">          <property alias="DOE 39" label="DOE 39" label-short="false" />        </line>        <line border="none">          <property alias="DOE 40" label="DOE 40" label-short="false" />        </line>        <line border="none">          <property alias="DOE 41" label="DOE 41" label-short="false" />        </line>        <line border="none">          <property alias="DOE 42" label="DOE 42" label-short="false" />        </line>        <line border="none">          <property alias="DOE 43" label="DOE 43" label-short="false" />        </line>        <line border="none">          <property alias="DOE 44" label="DOE 44" label-short="false" />        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim101502','dynamic.maSimsHelper.101502','MA SIMS Error 101502','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;101502</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;School code not valid for reason for reporting</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">If Reason for Reporting (DOE011) = 01 or 03 then the school code (DOE015) must refer to a public or charter school for most students.  Exiting students who are services only may report Home School or Pre-School in DOE015.</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Steps to resolve:</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">1. If DOE11 is 01 or 03\, verify the school code (DOE15) is a public or charter school.</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">2. Check if the &#39;Adjusted services only&#39; box is checked on the most recent E enrollment record under Student &gt; Membership.</text>          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Note:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">If the school ID (DOE15) is showing a different value in Aspen than the DESE error\, check the below membership records to verify an adjusted school ID isn&#39;t overriding the school .</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 11" label="DOE 11" label-short="false" />        </line>        <line border="none">          <property id="relStdSklOid.sklFieldA006" label="DOE 15" label-short="false" />        </line>      </block>    </row>    <row>      <block>        <line border="none">          <text underline="true" font-size="medium">ENROLLMENT HISTORY</text>        </line>        <line border="none">          <spacer height="2" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <embedded-list id="student-enrollment" relationship="relStdEnrOid" selection-type="none" embedded-edit="true" show-blob-text="true" warn-on-delete="true" independent-save="true">              <field alias="enr-date" sort="true" />              <field id="enrEnrType" />              <field id="enrEnrStatus" />              <field id="enrEnrCode" />              <field id="relEnrSklOid.sklSchoolName" />              <field alias="ENR Prev DOE Adjusted Status" />              <field alias="ENR Prev DOE Adjusted School" />              <field alias="ENR Prev DOE Adjusted Member" />              <field alias="ENR Prev DOE Adjusted Attend" />              <field alias="ENR Prev DOE 13" />              <field alias="ENR Prev DOE 11" />              <field alias="ENR Prev Calendar" />            </embedded-list>          </cell>        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim101507','dynamic.maSimsHelper.101507','MA SIMS Error 101507','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;101507</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Enrollment Status (DOE12)\, not valid with the school code</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">The school code (DOE015) for services only students and for transferred services only students (DOE012=40\,41) \, must be the code for the school they are enrolled in\, not the school code where they receive services.&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 12" label="DOE 12" label-short="false" />        </line>        <line border="none">          <property id="relStdSklOid.sklFieldA006" label="DOE 15" label-short="false" />        </line>      </block>    </row>    <row>      <block>        <line border="none">          <text underline="true" font-size="medium">ENROLLMENT HISTORY</text>        </line>        <line border="none">          <spacer height="2" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <embedded-list id="student-enrollment" relationship="relStdEnrOid" selection-type="none" embedded-edit="true" show-blob-text="true" warn-on-delete="true" independent-save="true">              <field alias="enr-date" sort="true" />              <field id="enrEnrType" />              <field id="enrEnrStatus" />              <field id="enrEnrCode" />              <field id="relEnrSklOid.sklSchoolName" />              <field alias="ENR Prev DOE Adjusted Status" />              <field alias="ENR Prev DOE Adjusted School" />              <field alias="ENR Prev DOE Adjusted Member" />              <field alias="ENR Prev DOE Adjusted Attend" />              <field alias="ENR Prev DOE 13" />              <field alias="ENR Prev DOE 11" />              <field alias="ENR Prev Calendar" />            </embedded-list>          </cell>        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim101508','dynamic.maSimsHelper.101508','MA SIMS Error 101508','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;101508</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">Public/Charter School not valid for report/enroll code</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">If Reason for Reporting (DOE011) = 01 or 03 then DOE016 must be a grade within the reported school (DOE015) in the reporting district.</text>            <spacer height="15" />          </cell>        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">If the values for DOE011\, DOE015 and DOE016 are correct\, publish StudentPersonal and StudentSchoolEnrollment.</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 12" label="DOE 12" label-short="false" />        </line>        <line border="none">          <property alias="DOE 15" label="DOE 15" label-short="false" />        </line>        <line border="none">          <property id="stdGradeLevel" label="DOE 16" label-short="false" />        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim101510','dynamic.maSimsHelper.101510','MA SIMS Error 101510','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;101510</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Days In Membership = 0 is invalid</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">The Summer Dates for the current school year need to be setup at the start of the new school year to prepare for the October State Reporting.</text>            <spacer height="15" />          </cell>        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">This can be set in District View &gt; District &gt; Setup &gt; Details\, SIF Configuration.</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Steps to resolve:</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">1. The First and Last In Session dates of the school calendar need to match the Start and End dates of the Schedule Terms\, this includes FY\, T1\, Q1\, S1\, etc. If this was updated\, Publish All for topic TermInfo.</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">2. The First Step is to SIF Publish All - StudentSchoolEnrollment and TermInfo</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">3. Locate the Student (if there is more than 1\, make a Snapshot)</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">4. Go to District View\, Tools &gt; Exports &gt; Filter to SIF &gt; SIF Student Topic Export &gt; and run the following topics for the Snapshot of Students: "StudentAttendanceSummary"</text>          </cell>        </line>        <line border="none">          <text bold="true" font-size="medium">Is the Student/Snapshot exporting correctly?</text>          <spacer width="5" />        </line>        <line border="none">          <spacer height="15" width="10" />          <text font-size="medium">If not:</text>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">1. Check the student(s) attendance. There can only be attendance in DOE017 and DOE018 or in the Adjusted Fields\, not both. 555 is no longer a valid value for SIF\, only Legacy.</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">2. Check the Membership Records for EnrPrev Adj Attendance on the most recent W record and clear if needed.</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">3. If the Student has a Summer Withdrawal\, check the Change History on that W record to see if it was ever sent with a date during the School Year. If this is the case\, you may need to send a delete for the previous E record (the one with the RefId)\, then send a change for StudentSchoolEnrollment. This will clear the old exit date from the State&#39;s records.</text>          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Note:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">Sometimes just re-publishing &lt;strong&gt;StudentPersonal&lt;/strong&gt; and &lt;strong&gt;StudentSchoolEnrollment&lt;/strong&gt; will clear the error.</text>            <spacer width="15" />          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">Once the Student is exporting correctly\, we need to either wait until attendance is pulled overnight or we can ask the state to pull it right away.</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 17" label="DOE 17" label-short="false" />        </line>        <line border="none">          <property alias="DOE 18" label="DOE 18" label-short="false" />        </line>      </block>    </row>    <row>      <block>        <line border="none">          <text underline="true" font-size="medium">ENROLLMENT HISTORY</text>        </line>        <line border="none">          <spacer height="2" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <embedded-list id="student-enrollment" relationship="relStdEnrOid" selection-type="none" embedded-edit="true" show-blob-text="true" warn-on-delete="true" independent-save="true">              <field alias="enr-date" sort="true" />              <field id="enrEnrType" />              <field id="enrEnrStatus" />              <field id="enrEnrCode" />              <field id="relEnrSklOid.sklSchoolName" />              <field alias="ENR Prev DOE Adjusted Status" />              <field alias="ENR Prev DOE Adjusted School" />              <field alias="ENR Prev DOE Adjusted Member" />              <field alias="ENR Prev DOE Adjusted Attend" />              <field alias="ENR Prev DOE 13" />              <field alias="ENR Prev DOE 11" />              <field alias="ENR Prev Calendar" />            </embedded-list>          </cell>        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim101524','dynamic.maSimsHelper.101524','MA SIMS Error 101524','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;101524</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Enrollment not valid with Private school&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">Enrollment Status code (DOE012) must not equal to 01 if the school is a private\, parochial or a profit private school.(org type11)&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>	<row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Steps to resolve:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">If this student is at a private school\, update their DOE 12 value.</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>		<line border="none">          <property id="relStdSklOid.sklFieldA006" label="DOE 15" label-short="false" />        </line>        <line border="none">          <property alias="DOE Adjusted School" label="Adjusted School" label-short="false" />        </line>		<line border="none">          <property alias="DOE 12" label="DOE 12" label-short="false" />        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim101535','dynamic.maSimsHelper.101535','MA SIMS Error 101535','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;101535</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;DOB does not match directory&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">DOB reported does not match the DOB in the student directory (provided in the error message).&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Steps to resolve:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">If this student&#39;s DOB was updated recently\, update this data on the student in the directory in the DESE portal.</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property id="relStdPsnOid.psnDob" label="Date of Birth" label-short="false" />        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim101572','dynamic.maSimsHelper.101572','MA SIMS Error 101572','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;101572</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">LN: Last Name does not match directory</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">Suffix should not be included in the last name in Aspen.</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Steps to resolve:</text>          <spacer height="15" />        </line>        <line border="none">          <spacer height="15" width="10" />          <text font-size="medium">If student was sent without a suffix and DESE has them with a suffix in their name:</text>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">1.  Add the suffix to the last name field (with a space)</text>          </cell>        </line>        <line border="none">          <spacer height="15" width="10" />          <text font-size="medium">If DESE has the student without a suffix and a suffix is attached:</text>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">1. The last name will need to be fixed on the DESE website by removing the suffix from the Last Name</text>          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property id="relStdPsnOid.psnNameLast" label="DOE 05" label-short="false" />        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim101573','dynamic.maSimsHelper.101573','MA SIMS Error 101573','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;101573</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;FN: First Name does not match directory&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">First Name reported does not match the First Name in the student directory (provided in the error message).&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Steps to resolve:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">If this student&#39;s first name was updated recently\, update this data on the student in the directory in the DESE portal.</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3