('VWTmaSim111507','dynamic.maSimsHelper.111507','MA SIMS Error 111507','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;111507</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Grade invalid with School Code&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">Private preschool or Nursery school (DOE015=00000001) can only have grade PK or SP(DOE016=PK or SP).&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Steps to resolve:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">If this student&#39;s grade level is not PK or SP\, they should not be in this school if DOE 15 is 00000001.</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&