('VWTmaSim011503','dynamic.maSimsHelper.11503','MA SIMS Error 11503','1','*dst',NULL,'<?xml version=\"1.0\" encoding=\"UTF-8\"?><template>  <tab name=\"tab.student.std.list.detail\">    <row>      <block>        <line border=\"bottom\" shaded=\"true\">          <text bold=\"true\" font-size=\"large\">&lt;span style=\"color:#00a3cc;\"&gt;Error Code:&lt;/span&gt;</text>          <text bold=\"true\" font-size=\"medium\">&amp;nbsp;11503</text>          <spacer height=\"15\" />        </line>        <line border=\"none\">          <cell border=\"none\" cell-span=\"1\" line-span=\"1\">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border=\"bottom\" shaded=\"true\">          <text bold=\"true\" font-size=\"medium\">Error Description:</text>          <text font-size=\"medium\">&amp;nbsp;Private or Approved Sped Grade not listed in reported school.&amp;nbsp;</text>          <spacer height=\"15\" />        </line>        <line border=\"none\">          <cell align=\"left\" border=\"none\" cell-span=\"1\" line-span=\"1\">            <text font-size=\"medium\">Student&#39;s grade (DOE016) not valid for the reported school (DOE015).&amp;nbsp;</text>            <spacer height=\"15\" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border=\"bottom\" shaded=\"true\">          <cell border=\"none\" cell-span=\"1\" line-span=\"1\" shaded=\"true\">            <text bold=\"true\" font-size=\"medium\">Steps to resolve:</text>          </cell>        </line>        <line border=\"bottom\">          <cell border=\"none\" cell-span=\"1\" line-span=\"1\">            <text font-size=\"medium\">Verify the grade levels listed for the school the student is enrolled in (District View &gt; Schools).</text>            <spacer width=\"15\" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border=\"bottom\" shaded=\"true\">          <text bold=\"