('VWTmaSim001323','dynamic.maSimsHelper.1323','MA SIMS Error 1323','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;1323</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;City of Birth is invalid&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">Certain names and abbreviations are not allowed for City of Birth (i.e. US\, USA\, America\, etc.).&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Steps to resolve:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">Verify City of Birth is populated\, correct\, and does not contain any abbreviations.</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 08" label="City of Birth" label-short="false" />        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim001327','dynamic.maSimsHelper.1327','MA SIMS Error 1327','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;1327</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;SPED placement age 6:21 (DOE034) invalid&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">If Sped Placement (DOE032) = 45 or Sped Placement (DOE034)= 90\, then school code (DOE015) can only be 037000xx (one of the institutional schools) or 09200300 or 09200500. &amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Steps to resolve:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">If the student has an adjusted school code\, verify it is up to date\, as well as DOE 34.</text>            <spacer width="15" />          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">If the student is age 6 or older\, their DOE 34 value needs to be populated with a value other than 00.</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property id="relStdSklOid.sklFieldA006" label="DOE 15:" label-short="false" />        </line>        <line border="none">          <property alias="DOE Adjusted School" label="Adjusted School" label-short="false" />        </line>        <line border="none">          <property alias="DOE 32" label="DOE 32" label-short="false" />        </line>        <line border="none">          <property alias="DOE 34" label="DOE 34" label-short="false" />        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim001329','dynamic.maSimsHelper.1329','MA SIMS Error 1329','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;1329</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Student SASID not found in student directory. Invalid SASID.&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">There is no SASID with that sequence of numbers in the student directory. Usually\, it&#39;s a typo with one of the numbers.&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Steps to resolve:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">Verify the SASID of this student is correct. Publish StudentPersonal for this student if necessary.</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE SASID" label="SASID" label-short="false" />        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim001331','dynamic.maSimsHelper.1331','MA SIMS Error 1331','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;1331</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Race code is invalid&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">The code entered is invalid. Refer to valid values for DOE010 in the Data Handbook.&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Steps to resolve:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">Verify the code for race (DOE010) is populated and the state code on the chosen reference table entry is listed in &lt;a href="http://www.doe.mass.edu/infoservices/data/sims/SIMS-DataHandbook.pdf"&gt;the SIMS Data Handbook&lt;/a&gt;\, page 18</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <text bold="true" font-size="medium">DOE 010 Race/Ethnicity</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <property id="relStdPsnOid.psnHispLatInd" label-display="right" label-short="false" />          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <embedded-list detail-context="person.race.popup" id="races" popup-height="125" popup-width="350" relationship="relStdPsnOid.relPsnRacOid" selection-type="multiple">              <field id="racRaceCode" sort="true" />            </embedded-list>          </cell>        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim001333','dynamic.maSimsHelper.1333','MA SIMS Error 1333','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;1333&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Enrollment status code is invalid&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Students who are SPED Only - Student should be active (01)</text>          <spacer height="15" />        </line>        <line border="none">          <text bold="true" font-size="medium">Steps to resolve:</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">1. DOE Adjusted Enrollment Status should be SPED Only (40)</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">2. DOE Adjusted School ID: Needs to have an adjusted school entered.</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">3. Most current membership Enrollment should be an "E" as Active and SPED only marked True.&amp;nbsp;</text>          </cell>        </line>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Students who are not SPED only&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <text bold="true" font-size="medium">Steps to resolve:</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">1. The student should have a "W" record as the most current membership record.</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">2. In the most current "W" record Previous Adjusted DOE 12 should be blank.</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">3. In the most current "W" record\, enrollment status should match the enrollment status on the Student record.</text>          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 11" label="DOE 11" label-short="false" />        </line>        <line border="none">          <property alias="DOE 12" label="DOE 12" label-short="false" />        </line>        <line border="none">          <property alias="DOE 13" label="DOE 13" label-short="false" />        </line>        <line border="none">          <property alias="DOE Adjusted Status" label="Adjusted Status" label-short="false" />        </line>        <line border="none">          <property alias="DOE Adjusted School" label="Adjusted School" label-short="false" />        </line>      </block>    </row>    <row>      <block>        <line border="none">          <text underline="true" font-size="medium">ENROLLMENT HISTORY</text>        </line>        <line border="none">          <spacer height="2" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <embedded-list id="student-enrollment" relationship="relStdEnrOid" selection-type="none" embedded-edit="true" show-blob-text="true" warn-on-delete="true" independent-save="true">              <field alias="enr-date" sort="true" />              <field id="enrEnrType" />              <field id="enrEnrStatus" />              <field id="enrEnrCode" />              <field id="relEnrSklOid.sklSchoolName" />              <field alias="ENR Prev DOE Adjusted Status" />              <field alias="ENR Prev DOE Adjusted School" />              <field alias="ENR Prev DOE Adjusted Member" />              <field alias="ENR Prev DOE Adjusted Attend" />              <field alias="ENR Prev DOE 13" />              <field alias="ENR Prev DOE 11" />              <field alias="ENR Prev Calendar" />            </embedded-list>          </cell>        </line>      </block>    </row>  </tab></template>'),
