('VWTmaSim001361','dynamic.maSimsHelper.1361','MA SIMS Error 1361','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;1361</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;ELL: English Learners Program code is invalid&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">The code entered is invalid.  Refer to valid values for DOE026 - English Language Learners Program status in the Data Handbook.&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Steps to resolve:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">Verify the value for English Learners Program Status (DOE026) is populated and one of the values listed in &lt;a href="http://www.doe.mass.edu/infoservices/data/sims/SIMS-DataHandbook.pdf"&gt;the SIMS Data Handbook&lt;/a&gt;\, page 35</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 26" label="English Language Education Program Status" label-short="false" />        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim001364','dynamic.maSimsHelper.1364','MA SIMS Error 1364','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;1364</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Days In Membership must be less than 261 days&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">Days in membership cannot be greater than 261 days. Do not count weekends or holidays for residential placements.&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Steps to resolve:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">If Adjusted Membership is populated\, verify the value is not greater than 261.</text>            <spacer width="15" />          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">If there are multiple enrollment spans within the current year\, move the value from Adjusted Membership to the field "Prev Adj Membership" on the most recent E record.</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE Adjusted Membership" label="Adjusted Membership" label-short="false" />        </line>      </block>    </row>    <row>      <block>        <line border="none">          <text underline="true" font-size="medium">ENROLLMENT HISTORY</text>        </line>        <line border="none">          <spacer height="2" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <embedded-list id="student-enrollment" relationship="relStdEnrOid" selection-type="none" embedded-edit="true" show-blob-text="true" warn-on-delete="true" independent-save="true">              <field alias="enr-date" sort="true" />              <field id="enrEnrType" />              <field id="enrEnrStatus" />              <field id="enrEnrCode" />              <field id="relEnrSklOid.sklSchoolName" />              <field alias="ENR Prev DOE Adjusted Status" />              <field alias="ENR Prev DOE Adjusted School" />              <field alias="ENR Prev DOE Adjusted Member" />              <field alias="ENR Prev DOE Adjusted Attend" />              <field alias="ENR Prev DOE 13" />              <field alias="ENR Prev DOE 11" />              <field alias="ENR Prev Calendar" />            </embedded-list>          </cell>        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim001365','dynamic.maSimsHelper.1365','MA SIMS Error 1365','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;1365</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Days In Attendance must be between 0 and 261&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">Days in attendance must not be less than 0 or greater than 261.&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Steps to resolve:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">If Adjusted Attendance is populated\, verify the value is not greater than 261 or less than 0.</text>            <spacer width="15" />          </cell>        </line>		<line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">If there are multiple enrollment spans within the current year\, move the value from Adjusted Attendance to the field "Prev Adj Attendance" on the most recent E record.</text>            <spacer width="15" />          </cell>        </line>		<line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">Wait for attendance to pull overnight.</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE Adjusted Attendance" label="Adjusted Attendance" label-short="false" />        </line>      </block>    </row>	<row>      <block>        <line border="none">          <text underline="true" font-size="medium">ENROLLMENT HISTORY</text>        </line>        <line border="none">          <spacer height="2" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <embedded-list id="student-enrollment" relationship="relStdEnrOid" selection-type="none" show-blob-text="true" embedded-edit="true" warn-on-delete="true" independent-save="true">              <field alias="enr-date" sort="true" sort-direction="desc"/>              <field id="enrEnrType" />              <field id="enrEnrStatus" />              <field id="enrEnrCode" />              <field id="relEnrSklOid.sklSchoolName" />              <field alias="ENR Prev DOE Adjusted Status" />              <field alias="ENR Prev DOE Adjusted School" />              <field alias="ENR Prev DOE Adjusted Member" />              <field alias="ENR Prev DOE Adjusted Attend" />              <field alias="ENR Prev DOE 13" />              <field alias="ENR Prev DOE 11" />              <field alias="ENR Prev Calendar" />            </embedded-list>          </cell>        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim001366','dynamic.maSimsHelper.1366','MA SIMS Error 1366','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;1366&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Having no days in attendance (D0E017) is not likely with reported days in membership (DOE018) &amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <text font-size="medium">The number of days of membership (DOE018) is not likely for an enrolled student (DOE012 equals 01 or 40) with no days of attendance (DOE017).&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <text font-size="medium">This error commonly occurs for a student who has been out due to medical issues at the start of the year. In such a situation\, an exception can be requested from DESE.&amp;nbsp;</text>          <spacer height="15" />        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 17" label="DOE 17" label-short="false" />        </line>        <line border="none">          <property alias="DOE 18" label="DOE 18" label-short="false" />        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim001376','dynamic.maSimsHelper.1376','MA SIMS Error 1376','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;1376</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">Days in Attendance not valid for out:placed student(s)&amp;nbsp;</text>          <spacer height="15" />        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Steps to resolve:</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">1. Verify that there are any previous attendance values on membership records</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">2. Verify that the there are no values in the adjusted days in attendance or days in membership on the the student record</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">3. If you make any changes publish SIMS topics using the SIF Publish Student Objects procedure in District View &gt; Tools &gt; Procedures for the effected student or snapshot.</text>          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE Adjusted Attendance" label="DOE Adjusted Attendance" label-short="false" />        </line>        <line border="none">          <property alias="DOE Adjusted Membership" label="DOE Adjusted Membership" label-short="false" />        </line>      </block>    </row>    <row>      <block>        <line border="none">          <text underline="true" font-size="medium">ENROLLMENT HISTORY</text>        </line>        <line border="none">          <spacer height="2" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <embedded-list id="student-enrollment" relationship="relStdEnrOid" selection-type="none" embedded-edit="true" show-blob-text="true" warn-on-delete="true" independent-save="true">              <field alias="enr-date" sort="true" />              <field id="enrEnrType" />              <field id="enrEnrStatus" />              <field id="enrEnrCode" />              <field id="relEnrSklOid.sklSchoolName" />              <field alias="ENR Prev DOE Adjusted Status" />              <field alias="ENR Prev DOE Adjusted School" />              <field alias="ENR Prev DOE Adjusted Member" />              <field alias="ENR Prev DOE Adjusted Attend" />              <field alias="ENR Prev DOE 13" />              <field alias="ENR Prev DOE 11" />              <field alias="ENR Prev Calendar" />            </embedded-list>          </cell>        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim001383','dynamic.maSimsHelper.1383','MA SIMS Error 1383','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;1383</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Sped Placement age 6:21 not valid with reason for reporting</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">If Sped Placement age 6-21 (DOE034) is anything other than 00\, then all other special education data elements must be reported. Or\, If Sped Placement age 3-5 (DOE032) is anything other than 00 or 05\, then all other special education data elements must be reported.&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Note:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">If you make any changes\, you may need to publish StudentPersonal and StudentSchoolEnrollment</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 32" label="DOE 32" label-short="false" />        </line>        <line border="none">          <property alias="DOE 33" label="DOE 33" label-short="false" />        </line>        <line border="none">          <property alias="DOE 34" label="DOE 34" label-short="false" />        </line>        <line border="none">          <property alias="DOE 35" label="DOE 35" label-short="false" />        </line>        <line border="none">          <property alias="DOE 36" label="DOE 36" label-short="false" />        </line>        <line border="none">          <property alias="DOE 37" label="DOE 37" label-short="false" />        </line>        <line border="none">          <property alias="DOE 38" label="DOE 38" label-short="false" />        </line>        <line border="none">          <property alias="DOE 39" label="DOE 39" label-short="false" />        </line>        <line border="none">          <property alias="DOE 40" label="DOE 40" label-short="false" />        </line>        <line border="none">          <property alias="DOE 41" label="DOE 41" label-short="false" />        </line>        <line border="none">          <property alias="DOE 42" label="DOE 42" label-short="false" />        </line>        <line border="none">          <property alias="DOE 43" label="DOE 43" label-short="false" />        </line>        <line border="none">          <property alias="DOE 44" label="DOE 44" label-short="false" />        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim001407','dynamic.maSimsHelper.1407','MA SIMS Error 1407','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;1407</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Days total: UnexcusedDays + DaysAttendance Greater than Days in membership</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">DOE Summary of the validation</text>            <spacer height="15" />          </cell>        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">Unexcused absences (DOE052) + days in attendance (DOE017) cannot be greater than the days in membership (DOE018).</text>            <spacer height="15" />          </cell>        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">Elements affected: DOE052 - Unexcused Student Absences\, DOE017 - Days in Attendance\, DOE018 - Days in Membership</text>            <spacer height="15" />          </cell>        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">Reporting periods where validation is used: OCT\,MAR\,EOY</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Steps to resolve:</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">Resolution 1</text>            <spacer height="15" />          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">1. The student&#39;s more current "W" record has "ENR Prev DOE Adjusted Attend" and "ENR Prev DOE Adjusted Member" fields populated.</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">2. In the most current "W" record\, "ENR Prev DOE Adjusted Attend" and "ENR Prev DOE Adjusted Member" should be blank.</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">3. Publish &#39;studentSchoolEnrollment&#39; for affected students using SIF Publish Select Student Objects under District View &gt; Tools &gt; Procedures.</text>          </cell>        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">Resolution 2</text>            <spacer height="15" />          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">1. Verify that the student record doesn&#39;t have values populated in both DOE17/DOE18 and Adjusted Attendance/Adjusted Membership. It needs to be one or the other\, not both.</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">2. If values are removed\, the error won&#39;t clear until Attendance has been pulled.</text>          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 17" label="DOE 17" label-short="false" />        </line>        <line border="none">          <property alias="DOE 18" label="DOE 18" label-short="false" />        </line>        <line border="none">          <property alias="DOE Adjusted Attendance" label="Adjusted Attendance" label-short="false" />        </line>        <line border="none">          <property alias="DOE Adjusted Membership" label="Adjusted Membership" label-short="false" />        </line>      </block>    </row>    <row>      <block>        <line border="none">          <text underline="true" font-size="medium">ENROLLMENT HISTORY</text>        </line>        <line border="none">          <spacer height="2" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <embedded-list id="student-enrollment" relationship="relStdEnrOid" selection-type="none" embedded-edit="true" show-blob-text="true" warn-on-delete="true" independent-save="true">              <field alias="enr-date" sort="true" />              <field id="enrEnrType" />              <field id="enrEnrStatus" />              <field id="enrEnrCode" />              <field id="relEnrSklOid.sklSchoolName" />              <field alias="ENR Prev DOE Adjusted Status" />              <field alias="ENR Prev DOE Adjusted School" />              <field alias="ENR Prev DOE Adjusted Member" />              <field alias="ENR Prev DOE Adjusted Attend" />              <field alias="ENR Prev DOE 13" />              <field alias="ENR Prev DOE 11" />              <field alias="ENR Prev Calendar" />            </embedded-list>          </cell>        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim001501','dynamic.maSimsHelper.1501','MA SIMS Error 1501','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;1501</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;School Code is Invalid</text>          <spacer height="15" />        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">A new field has been added to the School table. It is called SIF SKL School Focus. This needs to be assigned to the value &#39;scheduling&#39; for Out of District Schools and SPED Only Schools. This value ensures that the Adjusted School Value is sent to the state.</text>        </line>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Steps to resolve:</text>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">1. Locate the Student for more that one student creation of a snapshot is recommended</text>            <break />            <text font-size="medium">2. Go to District View\, Tools &gt; Exports &gt; Filter to SIF &gt; SIF Student Topic Export and run the StudentSchoolEnrollment student or snapshot.</text>            <break />            <break />            <text font-size="medium">3. Verify that the School Code does appear on the DESE website: http://www.doe.mass.edu/infoservices/data/sims/schoolcodes.html</text>            <break />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="none">          <spacer height="15" />          <text bold="true" font-size="medium">Is the correct school ID being exported? Does it match the School ID on the Error? (ex. Does the student have an adjusted School ID\, but the error is showing the District ID?)</text>        </line>        <line border="none">          <text font-size="medium">For Students in an Out of District School or SPED Holding School with an Adjusted School ID\, that are getting the 1501 Error from the state that has the District School ID\, the State is looking for the Student to have the following values:</text>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer height="15" />            <text font-size="medium">DOE 11 = 02\, DOE 12 = 01 and DOE 13 = 07: This is how the Outplaced Students should report.</text>          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Note:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">If you want the student to report as DOE 11 = 01\, DOE 12 = 01 and DOE 13 = 01 then the student would need to be enrolled directly in the adjusted school.</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>      </block>    </row>    <row>      <block>        <line border="none">          <break />          <break />          <property alias="DOE 11" label="DOE 11" label-short="false" />          <break />          <property alias="DOE 12" label="DOE 12" label-short="false" />          <break />          <property alias="DOE 13" label="DOE 13" label-short="false" />          <break />        </line>      </block>    </row>    <row>      <block>        <line border="none">          <text underline="true" font-size="medium">ENROLLMENT HISTORY</text>        </line>        <line border="none">          <spacer height="2" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <embedded-list id="student-enrollment" relationship="relStdEnrOid" selection-type="none" embedded-edit="true" show-blob-text="true" warn-on-delete="true" independent-save="true">              <field alias="enr-date" sort="true" />              <field id="enrEnrType" />              <field id="enrEnrStatus" />              <field id="enrEnrCode" />              <field id="relEnrSklOid.sklSchoolName" />              <field alias="ENR Prev DOE Adjusted Status" />              <field alias="ENR Prev DOE Adjusted School" />              <field alias="ENR Prev DOE Adjusted Member" />              <field alias="ENR Prev DOE Adjusted Attend" />              <field alias="ENR Prev DOE 13" />              <field alias="ENR Prev DOE 11" />              <field alias="ENR Prev Calendar" />            </embedded-list>          </cell>        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim001503','dynamic.maSimsHelper.1503','MA SIMS Error 1503','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;1503</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Public or charter School/Grade not in reporting district</text>          <spacer height="15" />        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Steps to resolve:</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">1. Verify that the grade level being reported to the state is a grade level that school has set up.  This can be checked in School View &gt; School &gt; Setup &gt; Details.</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">2. Year of graduation needs to match the reporting grade on most recent "E" membership record.</text>          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 16" label="DOE 16" label-short="false" />        </line>      </block>    </row>    <row>      <block>        <line border="none">          <text underline="true" font-size="medium">ENROLLMENT HISTORY</text>        </line>        <line border="none">          <spacer height="2" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <embedded-list id="student-enrollment" relationship="relStdEnrOid" selection-type="none" embedded-edit="true" show-blob-text="true" warn-on-delete="true" independent-save="true">              <field alias="enr-date" sort="true" />              <field id="enrEnrType" />              <field id="enrEnrStatus" />              <field id="enrEnrCode" />              <field id="relEnrSklOid.sklSchoolName" />              <field alias="ENR Prev DOE Adjusted Status" />              <field alias="ENR Prev DOE Adjusted School" />              <field alias="ENR Prev DOE Adjusted Member" />              <field alias="ENR Prev DOE Adjusted Attend" />              <field alias="ENR Prev DOE 13" />              <field alias="ENR Prev DOE 11" />              <field alias="ENR Prev Calendar" />            </embedded-list>          </cell>        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim001505','dynamic.maSimsHelper.1505','MA SIMS Error 1505','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;1505</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Services Only students may not be enrolled in the reporting district.&amp;nbsp;</text>          <spacer height="15" />        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Steps to resolve:</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">1. Verify that the correct/most recent enrollment record is being sent via the StudentSchoolEnrollment topic.</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">2. If the wrong enrollment record is being sent\, and it is not sending the most recent one(s)\, make sure all of the E records either have a status of Active\, or have an S record after them with a status of Active.</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">3. Make sure the school code being sent is correct\, if not check the Adjusted school code on both the DOE SIMS Template and the membership records Previous Adjusted fields seen in the SIF Field Set.</text>          </cell>        </line>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">The following fields need to be populated with the values below:&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">DOE11=02\, DOE12=01\, DOE13=07.</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">The "DOE Adjusted School ID" needs to be populated with the school that they are attending for services.</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">The "Adjusted services only" check box needs to be checked in their most recent E membership record.</text>          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Note:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">NEW TO 2016-2017 SCHOOL YEAR: A new field has been added to the School table. It is called SIF SKL School Focus. This needs to be assigned to the value &#39;scheduling&#39; for Out of District Schools and SPED Only Schools. Essentially this value is set so that DESE will look at the Adjusted School Value.</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 11" label="DOE 11" label-short="false" />        </line>        <line border="none">          <property alias="DOE 12" label="DOE 12" label-short="false" />        </line>        <line border="none">          <property alias="DOE 13" label="DOE 13" label-short="false" />        </line>        <line border="none">          <property id="relStdSklOid.sklFieldA006" label="DOE 15" label-short="false" />        </line>        <line border="none">          <property alias="DOE Adjusted School" label="Adjusted School" label-short="false" />        </line>      </block>    </row>    <row>      <block>        <line border="none">          <text underline="true" font-size="medium">ENROLLMENT HISTORY</text>        </line>        <line border="none">          <spacer height="2" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <embedded-list id="student-enrollment" relationship="relStdEnrOid" selection-type="none" embedded-edit="true" show-blob-text="true" warn-on-delete="true" independent-save="true">              <field alias="enr-date" sort="true" />              <field id="enrEnrType" />              <field id="enrEnrStatus" />              <field id="enrEnrCode" />              <field id="relEnrSklOid.sklSchoolName" />              <field alias="ENR Prev DOE Adjusted Status" />              <field alias="ENR Prev DOE Adjusted School" />              <field alias="ENR Prev DOE Adjusted Member" />              <field alias="ENR Prev DOE Adjusted Attend" />              <field alias="ENR Prev DOE 13" />              <field alias="ENR Prev DOE 11" />              <field alias="ENR Prev Calendar" />            </embedded-list>          </cell>        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim001516','dynamic.maSimsHelper.1516','MA SIMS Error 1516','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;1516</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Title I Code applies only to Public/Charter&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">Title I Code applies only to Public or Charter schools.&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Steps to resolve:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">The Title I Participation value must reflect the Title I status of the school an individual is attending in at the time of reporting.</text>            <spacer width="15" />          </cell>        </line>		<line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium"> If a school does not offer Title 1 services or is a Collaborative then the Title I Participation value should 00.</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 20" label="Title I Participation" label-short="false" />        </line>		<line border="none">          <property id="relStdSklOid.sklFieldA006" label="DOE 15:" label-short="false" />        </line>		<line border="none">          <property alias="DOE 30" label="Title I Targeted Assistance Services" label-short="false" />        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim001518','dynamic.maSimsHelper.1518','MA SIMS Error 1518','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;1518</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Title I: School has schoolwide Title I. Students must be reported with DOE020=01 and DOE030=00</text>          <spacer height="15" />        </line>      </block>    </row>    <row>      <block>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">Make sure that the student is reporting the correct school view the StudentSchoolEnrollment topic</text>            <spacer width="15" />          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">If the student is supposed to be at a Title I school\, then they must have their DOE values set to the values specified in the error.</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 20" label="DOE 20" label-short="false" />        </line>        <line border="none">          <property alias="DOE 30" label="DOE 30" label-short="false" />        </line>      </block>    </row>    <row>      <block>        <line border="none">          <text underline="true" font-size="medium">ENROLLMENT HISTORY</text>        </line>        <line border="none">          <spacer height="2" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <embedded-list id="student-enrollment" relationship="relStdEnrOid" selection-type="none" embedded-edit="true" show-blob-text="true" warn-on-delete="true" independent-save="true">              <field alias="enr-date" sort="true" />              <field id="enrEnrType" />              <field id="enrEnrStatus" />              <field id="enrEnrCode" />              <field id="relEnrSklOid.sklSchoolName" />              <field alias="ENR Prev DOE Adjusted Status" />              <field alias="ENR Prev DOE Adjusted School" />              <field alias="ENR Prev DOE Adjusted Member" />              <field alias="ENR Prev DOE Adjusted Attend" />              <field alias="ENR Prev DOE 13" />              <field alias="ENR Prev DOE 11" />              <field alias="ENR Prev Calendar" />            </embedded-list>          </cell>        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim001519','dynamic.maSimsHelper.1519','MA SIMS Error 1519','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;1519</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Title I: Student must not have Title I Code = 01 (School Wide)&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">School is not approved for school-wide Title I services. Only schools that are Title I school-wide (School Wide) may submit students as Title I=01 (DOE020). (Exclude summer exits.)&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Steps to resolve:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">If the student&#39;s school isn&#39;t Title I school-wide\, change their Title I Participation value to a value other than 01.</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>		<line border="none">          <property alias="DOE 11" label="Reason for Reporting" label-short="false" />        </line>        <line border="none">          <property alias="DOE 20" label="Title I Participation" label-short="false" />        </line>		<line border="none">          <property id="relStdSklOid.sklFieldA006" label="DOE 15:" label-short="false" />        </line>      </block>    </row>	<row>      <block>        <line border="none">          <text underline="true" font-size="medium">ENROLLMENT HISTORY</text>        </line>        <line border="none">          <spacer height="2" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <embedded-list id="student-enrollment" relationship="relStdEnrOid" selection-type="none" show-blob-text="true" embedded-edit="true" warn-on-delete="true" independent-save="true">              <field alias="enr-date" sort="true" sort-direction="desc"/>              <field id="enrEnrType" />              <field id="enrEnrStatus" />              <field id="enrEnrCode" />              <field id="relEnrSklOid.sklSchoolName" />              <field alias="ENR Prev DOE Adjusted Status" />              <field alias="ENR Prev DOE Adjusted School" />              <field alias="ENR Prev DOE Adjusted Member" />              <field alias="ENR Prev DOE Adjusted Attend" />              <field alias="ENR Prev DOE 13" />              <field alias="ENR Prev DOE 11" />              <field alias="ENR Prev Calendar" />            </embedded-list>          </cell>        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim001520','dynamic.maSimsHelper.1520','MA SIMS Error 1520','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;1520</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp; Title I: School has no Title I.  Students must be reported with DOE020=00 and DOE030=00&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">School is listed as not having Title I but the student is reported with a Title I participation code. If the school is not a Title I school\, then Title I participation codes must be 00 (DOE020 and DOE030). (Exclude summer exits.)&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Steps to resolve:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">If the student&#39;s school does not have Title I\, change their Title I Participation and Title I Targeted Assistance Services value to 00.</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 20" label="Title I Participation" label-short="false" />        </line>		<line border="none">          <property alias="DOE 30" label="Title I Targeted Assistance Services" label-short="false" />        </line>		<line border="none">          <property id="relStdSklOid.sklFieldA006" label="DOE 15:" label-short="false" />        </line>      </block>    </row>	<row>      <block>        <line border="none">          <text underline="true" font-size="medium">ENROLLMENT HISTORY</text>        </line>        <line border="none">          <spacer height="2" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <embedded-list id="student-enrollment" relationship="relStdEnrOid" selection-type="none" show-blob-text="true" embedded-edit="true" warn-on-delete="true" independent-save="true">              <field alias="enr-date" sort="true" sort-direction="desc"/>              <field id="enrEnrType" />              <field id="enrEnrStatus" />              <field id="enrEnrCode" />              <field id="relEnrSklOid.sklSchoolName" />              <field alias="ENR Prev DOE Adjusted Status" />              <field alias="ENR Prev DOE Adjusted School" />              <field alias="ENR Prev DOE Adjusted Member" />              <field alias="ENR Prev DOE Adjusted Attend" />              <field alias="ENR Prev DOE 13" />              <field alias="ENR Prev DOE 11" />              <field alias="ENR Prev Calendar" />            </embedded-list>          </cell>        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim001521','dynamic.maSimsHelper.1521','MA SIMS Error 1521','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;1521</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp; District does not offer choice. Reason for Enrollment (DOE013) = 02 is invalid&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">Only districts who are accepting school choice students may use a Reason for Enrollment = 02 (school choice).&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Steps to resolve:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">Change this student&#39;s DOE 13 value to something other than 02.</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 13" label="DOE 13" label-short="false" />        </line>      </block>    </row>	<row>      <block>        <line border="none">          <text underline="true" font-size="medium">ENROLLMENT HISTORY</text>        </line>        <line border="none">          <spacer height="2" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <embedded-list id="student-enrollment" relationship="relStdEnrOid" selection-type="none" show-blob-text="true" embedded-edit="true" warn-on-delete="true" independent-save="true">              <field alias="enr-date" sort="true" sort-direction="desc"/>              <field id="enrEnrType" />              <field id="enrEnrStatus" />              <field id="enrEnrCode" />              <field id="relEnrSklOid.sklSchoolName" />              <field alias="ENR Prev DOE Adjusted Status" />              <field alias="ENR Prev DOE Adjusted School" />              <field alias="ENR Prev DOE Adjusted Member" />              <field alias="ENR Prev DOE Adjusted Attend" />              <field alias="ENR Prev DOE 13" />              <field alias="ENR Prev DOE 11" />              <field alias="ENR Prev Calendar" />            </embedded-list>          </cell>        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim001524','dynamic.maSimsHelper.1524','MA SIMS Error 1524','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail" validate="current" validation-rules="MA-DOE-1524" show-nav-buttons="false">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">Sending Status Reason For reporting/reason for enrollment invalid</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">If Reason for Reporting (DOE011) = 02 then Reason for Enrollment (DOE013) must = 06\, 07 or 09.</text>          <spacer height="15" />        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large" >&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line>          <property alias="DOE 11" label="DOE 11" />        </line>        <line>          <property alias="DOE 13" label="DOE 13" />        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim001526','dynamic.maSimsHelper.1526','MA SIMS Error 1526','1','*dst',NULL,'<?xml version=\"1.0\" encoding=\"UTF-8\"?><template>  <tab name=\"tab.student.std.list.detail\">    <row>      <block>        <line border=\"bottom\" shaded=\"true\">          <text bold=\"true\" font-size=\"large\">&lt;span style=\"color:#00a3cc;\"&gt;Error Code:&lt;/span&gt;</text>          <text bold=\"true\" font-size=\"medium\">1526&amp;nbsp;</text>          <spacer height=\"15\" />        </line>        <line border=\"bottom\" shaded=\"true\">          <text bold=\"true\" font-size=\"medium\">Error Description:</text>          <text font-size=\"medium\">&amp;nbsp;Charter School: Not valid Reason for Enrollment(A&#44;1)&amp;nbsp;</text>          <spacer height=\"15\" />        </line>        <line border=\"none\">          <text font-size=\"medium\">If reason for enrollment (DOE013)=03 and reason for reporting (DOE011) = 03&#44; then the school (DOE015) must be a charter school.</text>          <spacer height=\"15\" />        </line>      </block>    </row>    <row>      <block>        <line border=\"bottom\" shaded=\"true\">          <text bold=\"true\" font-size=\"large\">&lt;span style=\"color:#00a3cc;\"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border=\"none\">          <property id=\"relStdSklOid.sklFieldA002\" label=\"DOE 15:\" label-short=\"false\" />        </line>        <line border=\"none\">          <property alias=\"DOE Adjusted School\" label=\"Adjusted School\" label-short=\"false\" />        </line>        <line border=\"none\">          <property alias=\"DOE 11\" label-short=\"false\" />        </line>        <line border=\"none\">          <property alias=\"DOE 13\" label-short=\"false\" />        </line>      </block>    </row>  </tab></template>'),																																																																																																																																																																																																																																																																																																																																																																																																																																																																						  
('VWTmaSim001528','dynamic.maSimsHelper.1528','MA SIMS Error 1528','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">1528&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;TownCode inconsistent with Reason for Reporting(B)&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <text font-size="medium">If Reason for Reporting (DOE011)=03 (non-resident)\, then the Town of Residence code must be a non-member town of the district</text>          <spacer height="15" />        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property id="relStdPsnOid.relPsnAdrPhys.adrCity" label="DOE14" label-short="false" />        </line>        <line border="none">          <property alias="DOE Adjusted City" label-short="false" />        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim001551','dynamic.maSimsHelper.1551','MA SIMS Error 1551','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;1551</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:&amp;nbsp;</text>          <text font-size="medium">TownCode inconsistent with Reason for Reporting(01)</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">If Reason for Reporting (DOE011) = 01 (resident) - then the Town of Residence code (DOE014) must be a member town of the district (except for students receiving sped services).</text>          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Steps to resolve:</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">1. Verify that the town code is populated and has a valid state code.</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">2. Verify that the town code that is populated is a member town of the district.</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">3. Verify the values in Aspen match the values shown in the DESE error code.</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">4. If the above varies\, re-publish StudentPersonal and StudentSchoolEnrollment topics (District View &gt; Tools &gt; Procedures\, SIF Publish SELECT Student Objects)</text>          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 11" label="DOE 11" label-short="false" />        </line>        <line border="none">          <property id="relStdPsnOid.relPsnAdrPhys.adrCity" label="DOE 14" label-short="false" />        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim001559','dynamic.maSimsHelper.1559','MA SIMS Error 1559','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;1559</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Town of Residence: 888 valid only for students living out-of-state&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">Town of residence (DOE014) must be 888 for student living outside of MASS (except for students receiving sped services).&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Steps to resolve:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">If this student is living out of state\, make sure the student&#39;s City of Residence is set to 888.</text>            <spacer width="15" />          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">If this student is living in district\, make sure the student&#39;s address is up to date.</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 11" label="DOE 11" label-short="false" />        </line>        <line border="none">          <property alias="DOE 13" label="DOE 13" label-short="false" />        </line>        <line border="none">          <property id="relStdPsnOid.relPsnAdrPhys.adrCity" label="DOE 14" label-short="false" />        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim001590','dynamic.maSimsHelper.1590','MA SIMS Error 1590','1','*dst',NULL,'<?xml version=\"1.0\" encoding=\"UTF-8\"?><template> <tab name=\"tab.student.std.list.detail\"> <row> <block> <line border=\"bottom\" shaded=\"true\"> <text bold=\"true\" font-size=\"large\">&lt;span style=\"color:#00a3cc;\"&gt;Error Code:&lt;/span&gt;</text> <text bold=\"true\" font-size=\"medium\">&amp;nbsp;1590</text> <spacer height=\"15\" /> </line> <line border=\"none\"> <cell border=\"none\" cell-span=\"1\" line-span=\"1\"> <spacer /> </cell> </line> </block> </row> <row> <block> <line border=\"bottom\" shaded=\"true\"> <text bold=\"true\" font-size=\"medium\">Error Description:</text> <text font-size=\"medium\">&amp;nbsp;Enrollment status (DOE012)=04 (graduate) not valid when student not passed MCAS&amp;nbsp;</text> <spacer height=\"15\" /> </line> <line border=\"none\"> <cell align=\"left\" border=\"none\" cell-span=\"1\" line-span=\"1\"> <text font-size=\"medium\">Students cannot be coded as graduated (DOE012=04) if they did not pass MCAS (do not have a competency determination ). &amp;nbsp;</text> <spacer height=\"15\" /> </cell> </line> </block> </row> <row> <block> <line border=\"bottom\" shaded=\"true\"> <cell border=\"none\" cell-span=\"1\" line-span=\"1\" shaded=\"true\"> <text bold=\"true\" font-size=\"medium\">Steps to resolve:</text> </cell> </line> <line border=\"bottom\"> <cell border=\"none\" cell-span=\"1\" line-span=\"1\"> <text font-size=\"medium\">If this student hasn&#39;t passed MCAS&#44; they cannot graduate.</text> <spacer width=\"15\" /> </cell> </line> <line border=\"bottom\"> <cell border=\"none\" cell-span=\"1\" line-span=\"1\"> <text font-size=\"medium\">If this student is missing MCAS scores&#44; enter them and resubmit MCAS.</text> <spacer width=\"15\" /> </cell> </line> </block> </row> <row> <block> <line border=\"bottom\" shaded=\"true\"> <text bold=\"true\" font-size=\"large\">&lt;span style=\"color:#00a3cc;\"&gt;Fields To Review Below:&lt;/span&gt;</text> </line> <line border=\"none\"> <property alias=\"DOE 12\" label=\"DOE 12\" label-short=\"false\" /> </line> </block> </row> </tab></template>'),																																																																																																																																																																																																																																																																																																																																																																																																																																																																																																																																																											
