d resubmit MCAS.</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 12" label="DOE 12" label-short="false" />        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim001593','dynamic.maSimsHelper.1593','MA SIMS Error 1593','1','*dst',NULL,'<?xml version=\"1.0\" encoding=\"UTF-8\"?><template>  <tab name=\"tab.student.std.list.detail\">    <row>      <block>        <line border=\"bottom\" shaded=\"true\">          <text bold=\"true\" font-size=\"large\">&lt;span style=\"color:#00a3cc;\"&gt;Error Code:&lt;/span&gt;</text>          <text bold=\"true\" font-size=\"medium\">&amp;nbsp;1593</text>          <spacer height=\"15\" />        </line>        <line border=\"none\">          <cell border=\"none\" cell-span=\"1\" line-span=\"1\">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border=\"bottom\" shaded=\"true\">          <text bold=\"true\" font-size=\"medium\">Error Description:</text>          <text font-size=\"medium\">&amp;nbsp;Enrollment Status (DOE012) = 01 or 04 invalid when an SCS exception has been granted.&amp;nbsp;</text>          <spacer height=\"15\" />        </line>        <line border=\"none\">          <cell align=\"left\" border=\"none\" cell-span=\"1\" line-span=\"1\">            <text font-size=\"medium\">A student who has an SCS exception may not be reported as enrolled and retain that exception in a subsequent period. &amp;nbsp;</text>            <spacer height=\"15\" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border=\"bottom\" shaded=\"true\">          <cell border=\"none\" cell-span=\"1\" line-span=\"1\" shaded=\"true\">            <text bold=\"true\" font-size=\"medium\">Steps to resolve:</text>          </cell>        </line>        <line border=\"bottom\">          <cell border=\"none\" cell-span=\"1\" line-span=\"1\">            <text font-size=\"medium\">Verify the enrollment status and contact DESE if you need the exception removed.</text>            <spacer width=\"15\" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border=\"bottom\" shaded=\"true\">          <text bold=\"true\" font-size=\"large\">&lt;span style=\"color:#00a3cc;\"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border=\"none\">          <property alias=\"DOE 12\" label=\"DOE 12\" label-short=\"false\" />        </line>      </block>    </row>  </tab></template>'),																																																																																																																																																																																																																																																																																																																																																																																																																																																																																																																																																																																																							   
('VWTmaSim001610','dynamic.maSimsHelper.1610','MA SIMS Error 1610','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;1610</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Days in Membership exceeds maximum for collection period</text>          <spacer height="15" />        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Steps to resolve:</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">1. Change the date on W records to be one day before the E records and removed all "PREV" values. W and E records cannot happen on the same date</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">2. Remove Adjusted Attendance and Adjusted Membership values</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">3. Re-publish StudentPersonal and StudentSchoolEnrollment topics (District View &gt; Tools &gt; Procedures\, SIF Publi