('VWTmaSim001706','dynamic.maSimsHelper.1706','MA SIMS Error 1706','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;1706</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Only English Language Learners may report SLIFE.&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">Only ELL students (DOE025=01) may report as meeting SLIFE criteria.&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Steps to resolve:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">If this student&#39;s DOE 25 value is not 01\, DOE 41 cannot be checked.</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 25" label="DOE 25" label-short="false" />        </line>		<line border="none">          <property alias="DOE 41" label="SLIFE" label-short="false" />        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim000180','dynamic.maSimsHelper.180','MA SIMS Error 180','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">180&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">Days in Membership (DOE018) must accrue for enrolled students&amp;nbsp;</text>          <spacer height="15" />        </line>      </block>    </row>    <row>      <block>        <line border="none">          <text bold="true" font-size="medium">Steps to resolve:</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">1.  Look at the last in session date of school in the School Calendar (School View &gt; School &gt; Calendar &gt; Dates)</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">2. Make sure the last day of the Schedule is after the last day of school (School View &gt; School &gt; Schedules)</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">3. The FY term needs to have the last day of school from the schedule entered as the end date and all check boxes for the Grade Term Cover map need to be checked (School View &gt; Schedule &gt; Structure &gt; Terms &gt; Details)&amp;nbsp;</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">4. Remove adjusted values from membership records as needed.</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">5. (Attendance errors) When you enter adjusted attendance and membership in the student details\, it applies to any membership record for the current school year\, so it would double\, triple\, etc. You would need to put the adjusted values in the membership record for it to add up correctly. You can run the SIF Student Topic Export for StudentAttendanceSummary to see if the numbers are correct before attendance pulls.</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">6. Publish TermInfo (District View &gt; Tools &gt; Procedures\, SIF Publish All)</text>          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE Adjusted Attendance" label="Adjusted Attendance" label-short="false" />        </line>        <line border="none">          <property alias="DOE Adjusted Membership" label="Adjusted Membership" label-short="false" />        </line>      </block>    </row>    <row>      <block>        <line border="none">          <text underline="true" font-size="medium">ENROLLMENT HISTORY</text>        </line>        <line border="none">          <spacer height="2" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <embedded-list id="student-enrollment" relationship="relStdEnrOid" selection-type="none" embedded-edit="true" show-blob-text="true" warn-on-delete="true" independent-save="true">              <field alias="enr-date" sort="true" />              <field id="enrEnrType" />              <field id="enrEnrStatus" />              <field id="enrEnrCode" />              <field id="relEnrSklOid.sklSchoolName" />              <field alias="ENR Prev DOE Adjusted Status" />              <field alias="ENR Prev DOE Adjusted School" />              <field alias="ENR Prev DOE Adjusted Member" />              <field alias="ENR Prev DOE Adjusted Attend" />              <field alias="ENR Prev DOE 13" />              <field alias="ENR Prev DOE 11" />              <field alias="ENR Prev Calendar" />            </embedded-list>          </cell>        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim000020','dynamic.maSimsHelper.20','MA SIMS Error 20','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;20</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp; Days in Attendance/Membership=555 invalid for students already submitted in EOY with 555&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">A student cannot be reported in October with attendance/membership equal to 555 if the student was previously reported in EOY collection with attendance/membership of 555 (summer withdrawal).&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">If you receive this error\, please contact Technical Support for assistance.</text>        </line>        <line border="bottom">          <text bold="true" font-size="medium">Call: 888-244-1366\, option 1</text>        </line>      </block>    </row>    <row>      <block>        <line border="none">          <text underline="true" font-size="medium">ENROLLMENT HISTORY</text>        </line>        <line border="none">          <spacer height="2" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <embedded-list id="student-enrollment" relationship="relStdEnrOid" selection-type="none" embedded-edit="true" show-blob-text="true" warn-on-delete="true" independent-save="true">              <field alias="enr-date" sort="true" />              <field id="enrEnrType" />              <field id="enrEnrStatus" />              <field id="enrEnrCode" />              <field id="relEnrSklOid.sklSchoolName" />              <field alias="ENR Prev DOE Adjusted Status" />              <field alias="ENR Prev DOE Adjusted School" />              <field alias="ENR Prev DOE Adjusted Member" />              <field alias="ENR Prev DOE Adjusted Attend" />              <field alias="ENR Prev DOE 13" />              <field alias="ENR Prev DOE 11" />              <field alias="ENR Prev Calendar" />            </embedded-list>          </cell>        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim021526','dynamic.maSimsHelper.21526','MA SIMS Error 21526','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;21526</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Charter School: Not valid Reason for Reporting&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">If the school is a charter school then reason for reporting (DOE011) must = 03.&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Steps to resolve:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">If this student&#39;s school is a charter school\, change DOE 11 to 03.</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property id="relStdSklOid.sklFieldA006" label="DOE 15:" label-short="false" />        </line>		<line border="none">          <property alias="DOE Adjusted School" label="Adjusted School" label-short="false" />        </line>		<line border="none">          <property alias="DOE 11" label="DOE 11" label-short="false" />        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim000023','dynamic.maSimsHelper.23','MA SIMS Error 23','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;23&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Current or Former SPED (DOE034) must have placement 01\, 10-90</text>          <spacer height="15" />        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Steps to resolve:</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">1. For each of the students reporting a SPED error\, run the export "SIF Student Topic Export" (District View &gt; Tools &gt; Exports\, MASIF-STDTOPIC-EXP) for topic StudentSpecialEducationSummary to determine if a record is being sent to the state&amp;nbsp;</text>          </cell>        </line>        <line border="none">          <spacer height="15" width="10" />          <text font-size="medium">If the student does not export:</text>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">1. Current or Former SPED (DOE034) must have placement 01\, 10-90 (if student was SPED earlier in the year but isn&#39;t currently\, DOE34 needs to be 01)</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">2. Check that DOE 40 is not set to a value of 00.</text>          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Note:</text>          </cell>        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">For the student to have their SpecialEducationSummary object sent to the state\, they must meet certain criteria:</text>            <spacer height="15" />          </cell>        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">The student must have enrollment status equivalent to Active or have enrollment activity since the beginning of the year;</text>            <spacer height="15" />          </cell>        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">SPED Criteria:</text>            <spacer height="15" />          </cell>        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">The student has a DOE 40 state code equivalent: "01"\, "02"\, "03"\, "04"\, "05"\, "06"\, "07"\, "08"\, "09" or the student is a sped role model\, having a user code equivalent of "05" in DOE 32.</text>            <spacer height="15" />          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">&amp;nbsp;For SPED values to be pulled directly from the SIMS template the box "Lock Sped Values" on the template must be checked.&amp;nbsp;</text>            <spacer width="15" />          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">&amp;nbsp;SPED values should be maintained for exited students so that the SpecialEducationSummary object gets built correctly</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 12" label="DOE 12" label-short="false" />        </line>        <line border="none">          <property alias="DOE 32" label="DOE 32" label-short="false" />        </line>        <line border="none">          <property alias="DOE 34" label="DOE 34" label-short="false" />        </line>        <line border="none">          <property alias="DOE 36" label="DOE 36" label-short="false" />        </line>        <line border="none">          <property alias="DOE 38" label="DOE 38" label-short="false" />        </line>        <line border="none">          <property alias="DOE 40" label="DOE 40" label-short="false" />        </line>      </block>    </row>    <row>      <block>        <line border="none">          <text underline="true" font-size="medium">ENROLLMENT HISTORY</text>        </line>        <line border="none">          <spacer height="2" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <embedded-list id="student-enrollment" relationship="relStdEnrOid" selection-type="none" embedded-edit="true" show-blob-text="true" warn-on-delete="true" independent-save="true">              <field alias="enr-date" sort="true" />              <field id="enrEnrType" />              <field id="enrEnrStatus" />              <field id="enrEnrCode" />              <field id="relEnrSklOid.sklSchoolName" />              <field alias="ENR Prev DOE Adjusted Status" />              <field alias="ENR Prev DOE Adjusted School" />              <field alias="ENR Prev DOE Adjusted Member" />              <field alias="ENR Prev DOE Adjusted Attend" />              <field alias="ENR Prev DOE 13" />              <field alias="ENR Prev DOE 11" />              <field alias="ENR Prev Calendar" />            </embedded-list>          </cell>        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim000230','dynamic.maSimsHelper.230','MA SIMS Error 230','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;230</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;SPED- Current or Former SPED (DOE032) must have placement 01\, 30-48</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">A student who is reported with a significant value in DOE032 in the prior collection must report a significant value in DOE032 or DOE034 in the current collection</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Note:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">DOE values for exited students should left in place for the student to report correctly</text>            <spacer width="15" />          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">Students has an enrollment record outside the dates defined in the district calendar they will not pull as part of the SpecialEducationSummary.  These students will report with a 00s to the state.</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">None.</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="none">          <text underline="true" font-size="medium">ENROLLMENT HISTORY</text>        </line>        <line border="none">          <spacer height="2" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <embedded-list id="student-enrollment" relationship="relStdEnrOid" selection-type="none" embedded-edit="true" show-blob-text="true" warn-on-delete="true" independent-save="true">              <field alias="enr-date" sort="true" />              <field id="enrEnrType" />              <field id="enrEnrStatus" />              <field id="enrEnrCode" />              <field id="relEnrSklOid.sklSchoolName" />              <field alias="ENR Prev DOE Adjusted Status" />              <field alias="ENR Prev DOE Adjusted School" />              <field alias="ENR Prev DOE Adjusted Member" />              <field alias="ENR Prev DOE Adjusted Attend" />              <field alias="ENR Prev DOE 13" />              <field alias="ENR Prev DOE 11" />              <field alias="ENR Prev Calendar" />            </embedded-list>          </cell>        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim000024','dynamic.maSimsHelper.24','MA SIMS Error 24','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;24</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">Days in Membership Cannot accrue for unenrolled students&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">If Reason for Reporting=02 and Enrollment Status=06\,20\,21\,22\,23\,24\,30\, 31\, 32\, 33\, 34\, 35 or 36 (died\, transferred or dropped out) for the reporting period\, then days in membership for the reporting period cannot be greater than days in membership for the previous period.</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 11" label="DOE 11" label-short="false" />        </line>        <line border="none">          <property alias="DOE 12" label="DOE 12" label-short="false" />        </line>        <line border="none">          <property alias="DOE Adjusted Membership" label="DOE Adjusted Membership" label-short="false" />        </line>      </block>    </row>    <row>      <block>        <line border="none">          <text underline="true" font-size="medium">ENROLLMENT HISTORY</text>        </line>        <line border="none">          <spacer height="2" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <embedded-list id="student-enrollment" relationship="relStdEnrOid" selection-type="none" embedded-edit="true" show-blob-text="true" warn-on-delete="true" independent-save="true">              <field alias="enr-date" sort="true" />              <field id="enrEnrType" />              <field id="enrEnrStatus" />              <field id="enrEnrCode" />              <field id="relEnrSklOid.sklSchoolName" />              <field alias="ENR Prev DOE Adjusted Status" />              <field alias="ENR Prev DOE Adjusted School" />              <field alias="ENR Prev DOE Adjusted Member" />              <field alias="ENR Prev DOE Adjusted Attend" />              <field alias="ENR Prev DOE 13" />              <field alias="ENR Prev DOE 11" />              <field alias="ENR Prev Calendar" />            </embedded-list>          </cell>        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim000025','dynamic.maSimsHelper.25','MA SIMS Error 25','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;25</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Previous year graduates\, Aged Out\, Deceased should not be reported this year.&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">If a student was reported as Aged Out or Deceased in the previous year EOY collection\, s/he should not be reported at  all in the current collection.&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Steps to resolve:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">Set the DOE Status to Do Not Report and this error will clear overnight.</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE Status" label="DOE Status" label-short="false" />        </line>        <line border="none">          <property alias="DOE 11" label="DOE 11" label-short="false" />        </line>        <line border="none">          <property alias="DOE 12" label="DOE 12" label-short="false" />        </line>        <line border="none">          <property alias="DOE 13" label="DOE 13" label-short="false" />        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim000026','dynamic.maSimsHelper.26','MA SIMS Error 26','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;26</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:&amp;nbsp;</text>          <text font-size="medium">Previous year graduates should not be reported this year.&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">If a student was reported as a graduate in EOY collection\, s/he should not be reported in the current collection unless s/he is returning for SPED services.</text>          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Steps to resolve:</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">1. Create a Snapshot of Students getting this error.</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">2. Mass Update DOE Status to &#39;Do Not Report&#39;</text>          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Note:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">This can be caused by the Summer Start and Summer End dates not being populated with the proper dates for the updated year (District View &gt; District &gt; Setup &gt; Details &gt; SIF Configuration)</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE Status" label="DOE Status" label-short="false" />        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim301384','dynamic.maSimsHelper.301384','MA SIMS Error 301384','1','*dst',NULL,'<?xml version=\"1.0\" encoding=\"UTF-8\"?><template>  <tab name=\"tab.student.std.list.detail\">    <row>      <block>        <line border=\"bottom\" shaded=\"true\">          <text bold=\"true\" font-size=\"large\">&lt;span style=\"color:#00a3cc;\"&gt;Error Code:&lt;/span&gt;</text>          <text bold=\"true\" font-size=\"medium\">&amp;nbsp;301384</text>          <spacer height=\"15\" />        </line>        <line border=\"none\">          <cell border=\"none\" cell-span=\"1\" line-span=\"1\">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border=\"bottom\" shaded=\"true\">          <text bold=\"true\" font-size=\"medium\">Error Description:</text>          <text font-size=\"medium\">&amp;nbsp; SPED Placement code invalid with school code(DOE015).&amp;nbsp;</text>          <spacer height=\"15\" />        </line>        <line border=\"none\">          <cell align=\"left\" border=\"none\" cell-span=\"1\" line-span=\"1\">            <text font-size=\"medium\">Students reported as being placed in a Public Residential Institution (DOE032=45 or DOE034=90) should report an Institutional school in DOE015.&amp;nbsp;</text>            <spacer height=\"15\" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border=\"bottom\" shaded=\"true\">          <cell border=\"none\" cell-span=\"1\" line-span=\"1\" shaded=\"true\">            <text bold=\"true\" font-size=\"medium\">Steps to resolve:</text>          </cell>        </line>        <line border=\"bottom\">          <cell border=\"none\" cell-span=\"1\" line-span=\"1\">            <text font-size=\"medium\">Verify the school the student is enrolled in is correct for their SPED coding.</text>            <spacer width=\"15\" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border=\"bottom\" shaded=\"true\">          <text bold=\"true\" font-size=\"large\">&lt;span style=\"color:#00a3cc;\"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border=\"none\">          <property id=\"relStdSklOid.sklFieldA002\" label=\"DOE 15:\" label-short=\"false\" />        </line>        <line border=\"none\">          <property alias=\"DOE Adjusted School\" label=\"Adjusted School\" label-short=\"false\" />        </line>        <line border=\"none\">          <property alias=\"DOE 32\" label=\"DOE 32\" label-short=\"false\" />        </line>        <line border=\"none\">          <property alias=\"DOE 34\" label=\"DOE 34\" label-short=\"false\" />        </line>      </block>    </row>  </tab></template>'),																																																																																																																																																																																																																																																																																																																																																																																																																																																																																																																																																																																																																																																																																																													  
('VWTmaSim301510','dynamic.maSimsHelper.301510','MA SIMS Error 301510','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">301510</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Days in Membership invalid for Enrollment status code (Oct)</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">Days in membership (DOE018) must be 555 for summer exit (graduates\, Certificate of attainment\, Completed grade 12) students reported in October (DOE012=04\,10\,11)</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 12" label="DOE 12" label-short="false" />        </line>        <line border="none">          <property alias="DOE 17" label="DOE 17" label-short="false" />        </line>        <line border="none">          <property alias="DOE 18" label="DOE 18" label-short="false" />        </line>        <line border="none">          <property alias="DOE Adjusted Attendance" label="Adjusted Attendance" label-short="false" />        </line>        <line border="none">          <property alias="DOE Adjusted Membership" label="Adjusted Membership" label-short="false" />        </line>      </block>    </row>    <row>      <block>        <line border="none">          <text underline="true" font-size="medium">ENROLLMENT HISTORY</text>        </line>        <line border="none">          <spacer height="2" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <embedded-list id="student-enrollment" relationship="relStdEnrOid" selection-type="none" embedded-edit="true" show-blob-text="true" warn-on-delete="true" independent-save="true">              <field alias="enr-date" sort="true" />              <field id="enrEnrType" />              <field id="enrEnrStatus" />              <field id="enrEnrCode" />              <field id="relEnrSklOid.sklSchoolName" />              <field alias="ENR Prev DOE Adjusted Status" />              <field alias="ENR Prev DOE Adjusted School" />              <field alias="ENR Prev DOE Adjusted Member" />              <field alias="ENR Prev DOE Adjusted Attend" />              <field alias="ENR Prev DOE 13" />              <field alias="ENR Prev DOE 11" />              <field alias="ENR Prev Calendar" />            </embedded-list>          </cell>        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim031524','dynamic.maSimsHelper.31524','MA SIMS Error 31524','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;31524</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp; Sending Status: Non:Sending Student must go to Public or Charter school in own district&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">If Reason for Reporting (DOE011) = 01 or 03\, then the school must be a public or a charter school in own district.&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Steps to resolve:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">If this student&#39;s school is a charter school\, change DOE 11 to 03.</text>            <spacer width="15" />          </cell>        </line>		<line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">If this student&#39;s DOE 11 is correct\, then this student&#39;s school needs to be updated to their current school.</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property id="relStdSklOid.sklFieldA006" label="DOE 15:" label-short="false" />        </line>		<line border="none">          <property alias="DOE Adjusted School" label="Adjusted School" label-short="false" />        </line>		<line border="none">          <property alias="DOE 11" label="DOE 11" label-short="false" />        </line>		<line border="none">          <property alias="DOE 12" label="DOE 12" label-short="false" />        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim031526','dynamic.maSimsHelper.31526','MA SIMS Error 31526','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;31526</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Charter School: Not valid Reason for Enrollment&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">If the school is a charter school then reason for Enrollment (DOE013) must = 03.&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Steps to resolve:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">If this student&#39;s school is a charter school\, change DOE 13 to 03.</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property id="relStdSklOid.sklFieldA006" label="DOE 15:" label-short="false" />        </line>		<line border="none">          <property alias="DOE Adjusted School" label="Adjusted School" label-short="false" />        </line>		<line border="none">          <property alias="DOE 13" label="DOE 13" label-short="false" />        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim000390','dynamic.maSimsHelper.390','MA SIMS Error 390','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;390</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Student previously reported on 504 plan must continue to report as 504 plan&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">If a student was reported with a 504 plan in a prior period within the fiscal year\, then s/he must continue to be reported with a 504 plan in the current period (except summer exits).&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Steps to resolve:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">Set 504 Plan Status to "504"</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 39" label="504 Plan Status" label-short="false" />        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim000004','dynamic.maSimsHelper.4','MA SIMS Error 4','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;4</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;No students enrolled in school and/or grade level</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">All opened schools within the district and all existing grades within the school are expected to report enrollment.&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Steps to resolve:</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">An initial Publish of StudentPersonal and StudentSchoolEnrollment needs to be done using the SIF Publish All (District View &gt; Tools &gt; Procedures)</text>          </cell>        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim041524','dynamic.maSimsHelper.41524','MA SIMS Error 41524','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;41524&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Sending Status: Sending Student cannot go to Public or Charter school&amp;nbsp;</text>          <spacer height="15" />        </line>      </block>    </row>    <row>      <block>        <line border="none">          <text bold="true" font-size="medium">Steps to resolve:</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">1. If Reason for Reporting (DOE011) = 02 then the reported school code must not be a public or a charter school.</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">2. If the student is SPED or Outplaced\, the Adjusted School should be populated and the School should be set as a Scheduling School.</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">3. If any changes are made\, you will need to publish StudentPersonal and StudentSchoolEnrollment.&amp;nbsp;</text>          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 11" label="DOE 11" label-short="false" />        </line>        <line border="none">          <property alias="DOE 40" label="DOE 40" label-short="false" />        </line>        <line border="none">          <property alias="DOE Adjusted School" label="Adjusted School" label-short="false" />        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim041525','dynamic.maSimsHelper.41525','MA SIMS Error 41525','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;41525</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;PreSchool/HomeSchool only valid with enrollment status (DOE012) = 40 or 41</text>          <spacer height="15" />        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Steps to resolve:</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">1. If the student has a school code of PreSchool/HomeSchool\, DOE 12 needs to be updated to 40 or 41.</text>          </cell>        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer width="15" />            <text font-size="medium">2. If the student has a school code of PreSchool/HomeSchool\, the most recent enrollment record needs to have &#39;Adjusted services only&#39; checked and an adjusted school code value of PreSchool/HomeSchool.</text>          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 12" label="DOE 12" label-short="false" />        </line>        <line border="none">          <property id="relStdSklOid.sklFieldA006" label="DOE 15" label-short="false" />        </line>        <line border="none">          <property alias="DOE Adjusted School" label="Adjusted School" label-short="false" />        </line>      </block>    </row>    <row>      <block>        <line border="none">          <text underline="true" font-size="medium">ENROLLMENT HISTORY</text>        </line>        <line border="none">          <spacer height="2" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <embedded-list id="student-enrollment" relationship="relStdEnrOid" selection-type="none" embedded-edit="true" show-blob-text="true" warn-on-delete="true" independent-save="true">              <field alias="enr-date" sort="true" />              <field id="enrEnrType" />              <field id="enrEnrStatus" />              <field id="enrEnrCode" />              <field id="relEnrSklOid.sklSchoolName" />              <field alias="ENR Prev DOE Adjusted Status" />              <field alias="ENR Prev DOE Adjusted School" />              <field alias="ENR Prev DOE Adjusted Member" />              <field alias="ENR Prev DOE Adjusted Attend" />              <field alias="ENR Prev DOE 13" />              <field alias="ENR Prev DOE 11" />              <field alias="ENR Prev Calendar" />            </embedded-list>          </cell>        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim501524','dynamic.maSimsHelper.501524','MA SIMS Error 501524','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;501524</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Enrollment not valid with Approved Sped school&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">(02\, 01\, 07) or (02\, 01\, 02) must be reported in DOE011\, DOE012\, DOE013 for Approved Sped schools and collaboratives.(org type 2).&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Steps to resolve:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">If this student&#39;s school is an approved SPED school\, DOE 11 must be 02\, DOE 12 must be 01\, and DOE 13 must be either 02 or 07.</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>		<line border="none">          <property alias="DOE 11" label="DOE 11" label-short="false" />        </line>		<line border="none">          <property alias="DOE 12" label="DOE 12" label-short="false" />        </line>        <line border="none">          <property alias="DOE 13" label="DOE 13" label-short="false" />        </line>      </block>    </row>  </tab></template>'),
('VWTmaSim000575','dynamic.maSimsHelper.575','MA SIMS Error 575','1','*dst',NULL,'<?xml version="1.0" encoding="UTF-8"?><template>  <tab name="tab.student.std.list.detail">    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Error Code:&lt;/span&gt;</text>          <text bold="true" font-size="medium">&amp;nbsp;575</text>          <spacer height="15" />        </line>        <line border="none">          <cell border="none" cell-span="1" line-span="1">            <spacer />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="medium">Error Description:</text>          <text font-size="medium">&amp;nbsp;Non-Instructional Title I code (DOE030) is invalid&amp;nbsp;</text>          <spacer height="15" />        </line>        <line border="none">          <cell align="left" border="none" cell-span="1" line-span="1">            <text font-size="medium">Non-Instructional Title I code code is not one of the acceptable codes found in the SIMS Data Handbook.&amp;nbsp;</text>            <spacer height="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <cell border="none" cell-span="1" line-span="1" shaded="true">            <text bold="true" font-size="medium">Steps to resolve:</text>          </cell>        </line>        <line border="bottom">          <cell border="none" cell-span="1" line-span="1">            <text font-size="medium">Verify the value for Non-Instructional Title I Code (DOE030) is one of the values listed in &lt;a href="http://www.doe.mass.edu/infoservices/data/sims/SIMS-DataHandbook.pdf"&gt;the SIMS Data Handbook&lt;/a&gt;\, page 39</text>            <spacer width="15" />          </cell>        </line>      </block>    </row>    <row>      <block>        <line border="bottom" shaded="true">          <text bold="true" font-size="large">&lt;span style="color:#00a3cc;"&gt;Fields To Review Below:&lt;/span&gt;</text>        </line>        <line border="none">          <property alias="DOE 30" label="Non-Instructional Title I Code" label-short="false" />        </line>      </block>    </row>  </tab></template>'),
